final:
module parallel_load_register (
    input clk,
    input rst_n,
    input en,
    input [7:0] data,
    output reg [7:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        q <= 8'b00000000;
    else if (en)
        q <= data;
end

endmodule
